	@loaitien       nvarchar(200)   = 'USD', 
	@vendor         nvarchar(200), 
	@customer       nvarchar(200), 
	@dacdiem        nvarchar(max), 
	@bemat_sanpham  nvarchar(max), 
	@hinhanh1       varbinary(max),
	@create_by      nvarchar(50), 
	@update_by      nvarchar(50), 
	@carton_qty     float = 1,
	@n_weight decimal(18, 3) = 0,
	@g_weight decimal(18, 3) = 0,
	@mauuv nvarchar(50) = ''
)
AS
BEGIN

IF @ghichu IS NULL
  SET @ghichu = ''
  
    INSERT INTO tr_sanpham
    ( 
		 masp
	    , masp_khachhang
	    , masp_nhamay
		, ma_btp
		, ma_erp
	    , tensp
	    , tensp_vn
	    , hehang
	    , mausac
