	    , create_date
	    , update_by
	    , update_date
	    , carton_qty
	    , n_weight
	    , g_weight
	    , mauuv
    )
    VALUES
    ( 
		 @masp
	    , @masp_khachhang
	    , @masp_nhamay
		, @maBTP
		, @maERP
	    , @tensp
	    , @tensp_vn
	    , @hehang
	    , @mausac
	    , @loaisp
	    , @ketcau
	    , @ghichu
	    , @dai
	    , @rong
	    , @cao
	    , CONCAT(FORMAT(@dai, '0.##'), '*', FORMAT(@rong, '0.##'), '*', FORMAT(@cao, '0.##')) --, @kichthuoc
	    , @nguyenlieu
	    , @dvt
	    , CONCAT(FORMAT(@dai, '0.##'), '*', FORMAT(@rong, '0.##'), '*', FORMAT(@cao, '0.##')) --@quycach
	    , @m2
	    , @m3
	    --, @dai_carton
	    --, @rong_carton
	    --, @cao_carton
	    --, @cbm
	    , @dongia
	    , @loaitien
	    , @vendor
	    , @customer
	    , @dacdiem
	    , @bemat_sanpham
	    , @hinhanh1
	    , @create_by
	    , GETDATE()
	    , @update_by
	    , GETDATE()
	    , @carton_qty
	    , @n_weight
	    , @g_weight
	    , @mauuv
    )
END","parseAnalysis":{"readsTables":[],"writesTables":["dbo.tr_sanpham"],"flags":[],"suggestedTier":"B"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
